def process(data):
    threshold = {threshold}
    comparison = "{comparison}"

    if not isinstance(data, dict):
        return data

    operations = {{
        ">": lambda v: v > threshold,
        "<": lambda v: v < threshold,
        "==": lambda v: v == threshold,
        ">=": lambda v: v >= threshold,
        "<=": lambda v: v <= threshold
    }}

    if comparison not in operations:
        return data

    filter_func = operations[comparison]
    return {{k: v for k, v in data.items() if filter_func(v)}}

